<?php namespace App\Domains\Furniture\Http\Controllers; use Illuminate\Http\Request; use App\Domains\Furniture\Models\FurnitureItem; class FurnitureItemController { public function index() { return response()->json(FurnitureItem::all()); } public function store(Request $request) { $furniture = FurnitureItem::create($request->all()); return response()->json($furniture, 201); } public function show(FurnitureItem $furniture) { return response()->json($furniture); } public function update(Request $request, FurnitureItem $furniture) { $furniture->update($request->all()); return response()->json($furniture); } public function destroy(FurnitureItem $furniture) { $furniture->delete(); return response()->json(null, 204); } }
